BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?apsPkg ?apsName ?parent1 ?p1Name ?parent2 ?p2Name ?parent3 ?p3Name WHERE {
  VALUES ?apsPkg {
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control::Alignment%20and%20Phasing%20System::Systems%20Engineering::09%20Views::TMT-APS-SE::TMT-APS%20DDD>
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control::Alignment%20and%20Phasing%20System::Systems%20Engineering::09%20Views::TMT-APS-SE::TMT-APS%20Model%20Information>
  }

  ?apsPkg rdf:type vocab:package ;
          vocab:NamedElement_name ?apsName .

  OPTIONAL {
    ?apsPkg vocab:Element_owner ?parent1 .
    ?parent1 vocab:NamedElement_name ?p1Name .
  }
  OPTIONAL {
    ?parent1 vocab:Element_owner ?parent2 .
    ?parent2 vocab:NamedElement_name ?p2Name .
  }
  OPTIONAL {
    ?parent2 vocab:Element_owner ?parent3 .
    ?parent3 vocab:NamedElement_name ?p3Name .
  }
}

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?apsPkg ?apsName ?parentViaOwned ?pName WHERE {
  ?apsPkg rdf:type vocab:package ;
          vocab:NamedElement_name ?apsName .
  FILTER(?apsName = "TMT-APS DDD" || ?apsName = "TMT-APS Model Information")

  OPTIONAL {
    ?parentViaOwned vocab:Element_ownedElement+ ?apsPkg .
    ?parentViaOwned vocab:NamedElement_name ?pName .
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?p ?oName ?o WHERE {
  VALUES ?apsPkg {
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control::Alignment%20and%20Phasing%20System::Systems%20Engineering::09%20Views::TMT-APS-SE>
  }
  ?apsPkg ?p ?o .
  OPTIONAL { ?o vocab:NamedElement_name ?oName . }
} 
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?apsPkg ?apsName WHERE {
  ?apsPkg rdf:type vocab:package ;
          vocab:NamedElement_name ?apsName .
  FILTER(?apsName = "TMT-APS DDD" || ?apsName = "TMT-APS Model Information" || ?apsName = "TMT-APS-SE")
}

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?parent ?parentName ?relPred WHERE {
  BIND(<http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::09%2520Views::TMT-APS-SE> AS ?apsPkg)

  { 
    ?parent ?relPred ?apsPkg .
    VALUES ?relPred { vocab:Package_packagedElement vocab:Element_ownedElement vocab:Element_owner }
  }
  OPTIONAL { ?parent vocab:NamedElement_name ?parentName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?s ?sName ?p WHERE {
  BIND(<http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::09%2520Views::TMT-APS-SE> AS ?apsPkg)
  ?s ?p ?apsPkg .
  OPTIONAL { ?s vocab:NamedElement_name ?sName . }
  FILTER(?s != ?apsPkg)
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?top ?topName ?mid ?midName ?apsPkg ?apsName WHERE {
  ?top rdf:type vocab:package ;
       vocab:NamedElement_name ?topName .
  FILTER(CONTAINS(LCASE(STR(?topName)), LCASE("work packages")))

  ?top vocab:Element_ownedElement+ ?apsPkg .
  ?apsPkg rdf:type vocab:package ;
          vocab:NamedElement_name ?apsName .
  FILTER(?apsName = "TMT-APS-SE")

  OPTIONAL {
    ?top vocab:Element_ownedElement+ ?mid .
    ?mid vocab:NamedElement_name ?midName .
    FILTER(CONTAINS(LCASE(STR(?midName)), LCASE("TMT-APS")))
  }
}
LIMIT 25
